+import { logger } from '../utils/logger.js';
+
+export type ProviderType = 'anthropic' | 'gemini' | 'openrouter' | 'onnx';
+
+export interface ProviderConfig {
+  name: ProviderType;
+  apiKey?: string;
+  baseUrl?: string;
+  priority: number; // 1 = highest priority
+  maxRetries: number;
+  timeout: number; // milliseconds
+  costPerToken: number; // USD per 1M tokens
+  enabled: boolean;
+  healthCheckInterval?: number; // milliseconds
+}
+
+export interface ProviderHealth {
+  provider: ProviderType;
+  isHealthy: boolean;
+  lastChecked: Date;
+  consecutiveFailures: number;
+  averageLatency: number; // milliseconds
+  successRate: number; // 0-1
+  errorRate: number; // 0-1
+  circuitBreakerOpen: boolean;
+}
+
+export interface ProviderMetrics {
+  provider: ProviderType;
+  totalRequests: number;
+  successfulRequests: number;
+  failedRequests: number;
+  totalTokens: number;
+  totalCost: number;
+  averageLatency: number;
+  lastUsed: Date;
+}
+
+export interface FallbackStrategy {
+  type: 'priority' | 'cost-optimized' | 'performance-optimized' | 'round-robin';
+  maxFailures: number; // Circuit breaker threshold
+  recoveryTime: number; // milliseconds before retry
+  retryBackoff: 'linear' | 'exponential';
+  costThreshold?: number; // Max USD per request
+  latencyThreshold?: number; // Max milliseconds
+}
+
+export class ProviderManager {
+  private providers: Map<ProviderType, ProviderConfig> = new Map();
+  private health: Map<ProviderType, ProviderHealth> = new Map();
+  private metrics: Map<ProviderType, ProviderMetrics> = new Map();
+  private strategy: FallbackStrategy;
+  private currentProvider: ProviderType | null = null;
+  private healthCheckIntervals: Map<ProviderType, NodeJS.Timeout> = new Map();
+
+  constructor(
+    providers: ProviderConfig[],
+    strategy: FallbackStrategy = {
+      type: 'priority',
+      maxFailures: 3,
+      recoveryTime: 60000, // 1 minute
+      retryBackoff: 'exponential'
+    }
+  ) {
+    this.strategy = strategy;
+    this.initializeProviders(providers);
+    this.startHealthChecks();
+  }
+
+  /**
+   * Initialize provider configurations
+   */
+  private initializeProviders(providers: ProviderConfig[]): void {
+    for (const provider of providers) {
+      this.providers.set(provider.name, provider);
+
+      // Initialize health tracking
+      this.health.set(provider.name, {
+        provider: provider.name,
+        isHealthy: true,
+        lastChecked: new Date(),
+        consecutiveFailures: 0,
+        averageLatency: 0,
+        successRate: 1.0,
+        errorRate: 0.0,
+        circuitBreakerOpen: false
+      });
+
+      // Initialize metrics
+      this.metrics.set(provider.name, {
+        provider: provider.name,
+        totalRequests: 0,
+        successfulRequests: 0,
+        failedRequests: 0,
+        totalTokens: 0,
+        totalCost: 0,
+        averageLatency: 0,
+        lastUsed: new Date()
+      });
+    }
+
+    logger.info('Provider Manager initialized', {
+      providers: Array.from(this.providers.keys()),
+      strategy: this.strategy.type
+    });
+  }
+
+  /**
+   * Start health check monitoring for all providers
+   */
+  private startHealthChecks(): void {
+    for (const [name, config] of this.providers.entries()) {
+      if (config.healthCheckInterval) {
+        const interval = setInterval(() => {
+          this.performHealthCheck(name);
