+  private async executeWithRetry<T>(
+    requestFn: (provider: ProviderType) => Promise<T>,
+    provider: ProviderType,
+    maxRetries: number
+  ): Promise<T> {
+    let lastError: Error | null = null;
+
+    for (let retry = 0; retry <= maxRetries; retry++) {
+      try {
+        // Apply backoff delay
+        if (retry > 0) {
+          const delay = this.calculateBackoffDelay(retry);
+          logger.debug('Retry backoff', { provider, retry, delay });
+          await new Promise(resolve => setTimeout(resolve, delay));
+        }
+
+        return await requestFn(provider);
+
+      } catch (error) {
+        lastError = error as Error;
+
+        // Check if error is retryable
+        if (!this.isRetryableError(error as Error)) {
+          throw error;
+        }
+
+        logger.debug('Retryable error, continuing', {
+          provider,
+          retry,
+          error: lastError.message
+        });
+      }
+    }
+
+    throw lastError || new Error('Max retries exceeded');
+  }
+
+  /**
+   * Calculate backoff delay
+   */
+  private calculateBackoffDelay(retry: number): number {
+    if (this.strategy.retryBackoff === 'exponential') {
+      // Exponential backoff: 1s, 2s, 4s, 8s, 16s...
+      return Math.min(1000 * Math.pow(2, retry), 30000); // Max 30s
+    } else {
+      // Linear backoff: 1s, 2s, 3s, 4s...
+      return Math.min(1000 * retry, 10000); // Max 10s
+    }
+  }
+
+  /**
+   * Check if error is retryable
+   */
+  private isRetryableError(error: Error): boolean {
+    const retryablePatterns = [
+      /rate limit/i,
+      /timeout/i,
+      /connection/i,
+      /network/i,
+      /503/,
+      /502/,
+      /429/
+    ];
+
+    return retryablePatterns.some(pattern => pattern.test(error.message));
+  }
+
+  /**
+   * Record successful request
+   */
+  private recordSuccess(provider: ProviderType, latency: number, tokens: number): void {
+    const metrics = this.metrics.get(provider);
