+  /**
+   * Generate cache key from request
+   */
+  generateKey(req: {
+    model?: string;
+    messages?: unknown[];
+    max_tokens?: number;
+    temperature?: number;
+    stream?: boolean;
+  }): string {
+    // Don't cache streaming requests
+    if (req.stream) {
+      return '';
+    }
+
+    const parts = [
+      req.model || 'default',
+      JSON.stringify(req.messages || []),
+      req.max_tokens?.toString() || '1000',
+      req.temperature?.toString() || '1.0'
+    ];
